/**
 * @file nx_network_codes.hpp
 * @brief Shared binary packet definitions for RK3588 ↔ Jetson NX communication
 * @author Generated by Claude Code
 * @version 1.0
 * @date 2025-06-12
 *
 * This header defines the wire format used between the RK3588 (robot side)
 * and the Jetson NX (compute side). Both sides include this header to ensure
 * binary compatibility.
 *
 * Integer fields use network byte order (htonl/ntohl).
 * Float fields are IEEE 754 — no conversion needed between aarch64 platforms.
 */

#pragma once

#include <cstdint>
#include <cstddef>

// ============================================================================
// Port assignments
// ============================================================================

/// Default port: RK3588 sends sensor + gamepad data to NX
constexpr int DEFAULT_SENSOR_PORT = 31001;

/// Default port: NX sends joint commands back to RK3588
constexpr int DEFAULT_COMMAND_PORT = 31002;

/// Local port that the receiver binds to (both sides)
constexpr int DEFAULT_LOCAL_RECV_PORT = 31002;
constexpr int DEFAULT_LOCAL_SEND_PORT = 31001;

// ============================================================================
// Packet: RK3588 → NX  (sensor data + user command)
// ============================================================================

struct SensorPacket {
    uint32_t seq;             ///< Monotonic sequence number (network byte order)
    uint32_t timestamp_ms;    ///< Millisecond timestamp from robot interface
    int32_t  current_state;   ///< RobotMotionState enum value
    float    rpy[3];          ///< Roll, pitch, yaw from IMU [rad]
    float    acc[3];          ///< Base linear acceleration [m/s²]
    float    omega[3];        ///< Body-frame angular velocity [rad/s]
    float    joint_pos[12];   ///< Joint positions [rad]
    float    joint_vel[12];   ///< Joint velocities [rad/s]
    float    joint_tau[12];   ///< Joint torques [Nm]
    float    cmd_vel[3];      ///< User command velocity: forward, side, turning (normalised)
};

/// Verify no padding surprises — all members are 4-byte aligned, no holes
static_assert(sizeof(SensorPacket) == 204,
    "SensorPacket size mismatch — check struct layout");
static_assert(offsetof(SensorPacket, rpy)       == 12, "rpy offset mismatch");
static_assert(offsetof(SensorPacket, joint_pos) == 48, "joint_pos offset mismatch");
static_assert(offsetof(SensorPacket, cmd_vel)   == 192,"cmd_vel offset mismatch");

// ============================================================================
// Packet: NX → RK3588  (joint commands)
// ============================================================================

struct CommandPacket {
    uint32_t seq;               ///< Monotonic sequence number from NX
    uint32_t heartbeat;         ///< Application-level heartbeat counter
    float    joint_pos_des[12]; ///< Desired joint positions [rad]
    float    joint_vel_des[12]; ///< Desired joint velocities [rad/s] (usually 0)
    float    kp[12];            ///< PD proportional gains
    float    kd[12];            ///< PD derivative gains
    float    tau_ff[12];        ///< Feed-forward torque [Nm]
};

static_assert(sizeof(CommandPacket) == 248,
    "CommandPacket size mismatch — check struct layout");
static_assert(offsetof(CommandPacket, joint_pos_des) == 8,  "joint_pos_des offset mismatch");
static_assert(offsetof(CommandPacket, kp)              == 104,"kp offset mismatch");
static_assert(offsetof(CommandPacket, tau_ff)          == 200,"tau_ff offset mismatch");

// ============================================================================
// Special sentinel values
// ============================================================================

/// NX sends seq == SHUTDOWN_SEQUENCE to request immediate JointDamping on RK3588
constexpr uint32_t SHUTDOWN_SEQUENCE = 0xFFFFFFFF;

/// Heartbeat value that signals the RK3588 should ignore this packet
constexpr uint32_t HEARTBEAT_SHUTDOWN = 0;
